var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>침식파 억제 시스템이 마비됐다! 실험 도중 러처가 탈출했어!</color>","JPN":"<color=#ffd34c>侵食波抑制システムが麻痺した！　実験の途中にラッチャーが脱走したぞ！</color>","ENG":"<color=#ffd34c>The Corruption Inhibitor system is down! Lurcher escaped during the experiment!</color>","TWN":"<color=#ffd34c>侵蝕波抑制系統癱瘓！實驗體在實驗過程中逃跑了！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>프리하트 박사는 어디에 있나! 셰퍼드가 사라졌다!</color>","JPN":"<color=#ffd34c>プラハト博士はどこにいる！　シェパードが消えた！</color>","ENG":"<color=#ffd34c>Where's Dr. Freeheart?! Shepherd's gone!</color>","TWN":"<color=#ffd34c>普立哈特博士在哪裡！牧羊犬不見了！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_RUNNING_02"},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>모든 출입문을 봉쇄해! 박사를 찾아!</color>","JPN":"<color=#ffd34c>すべての出入口を封鎖しろ！　博士を捜せ！</color>","ENG":"<color=#ffd34c>Block off all the exits! Find Dr. Freeheart!</color>","TWN":"<color=#ffd34c>封鎖所有出入口！找到博士！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>침식파장이 뒤섞인 비정상 차원이동 에너지 관측! 놈이 격리시설을 벗어나려고 합니다!</color>","JPN":"<color=#ffd34c>侵食波状が混ざった異常次元移動エネルギーを観測！　やつが隔離施設から出ようとしています！</color>","ENG":"<color=#ffd34c>Detecting an abnormal reading of dimensional jump energy mixed with Corruption rays! It is trying to escape the quarantine facility!</color>","TWN":"<color=#ffd34c>觀測到侵蝕波長中摻雜的異常次元移動能量！他正試圖逃離隔離設施！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>EM펄스 및 레벨3 블랙매터 사용을 허가한다! 시설 전체를 다운시키는 한이 있어도 놈이 벗어나는 건 막아!</color>","JPN":"<color=#ffd34c>EMパルスおよびレベル3のブラックマターの使用を許可する！　施設全体をダウンさせても、やつをここから出すな！</color>","ENG":"<color=#ffd34c>Permitting the use of EM pulses and Level 3 dark matter! Stop it from escaping even if it means shutting down the entire facility!</color>","TWN":"<color=#ffd34c>允許使用EM脈衝和3級暗物質！阻止他逃跑，哪怕摧毀整個設施！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_DIVE_EATER","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…찾았다.","JPN":"……見つけた。","ENG":"...Shepherd found it.","TWN":"……牧羊犬找到了。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"눈에 안 띄고, 시원한 곳.","JPN":"誰の目にも付かない、涼しいところ。","ENG":"An inconspicuous and cool place.","TWN":"這裡不太起眼，但很涼爽。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"얼음이 하나도 없어.","JPN":"氷が一つもない。","ENG":"There is no ice.","TWN":"不過這裡沒有冰塊。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그래도… 여기서 얌전히 기다려야 해. <color=#ffd34c>약속</color>했으니까.","JPN":"でも……ここでじっと待たないと。<color=#ffd34c>約束</color>したから。","ENG":"But still... Shepherd has to wait here. Because Shepherd <color=#ffd34c>promised</color>.","TWN":"但……牧羊犬必須耐心。因為<color=#ffd34c>約定</color>好了。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"러처도… 안전한 곳 찾았으면 좋겠다.","JPN":"ラッチャーも……安全なところが見つかればいいな。","ENG":"Shepherd also hopes... that Lurcher finds a safe place too.","TWN":"獵犬……也能找到一個安全的地方就好了。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>세포보존시스템 활성화. 스프리건 인자 집속부 급속동결 시작.</color>","JPN":"<color=#ffd34c>細胞保存システム活性化。スプリガン因子集束部の急速凍結開始。</color>","ENG":"<color=#ffd34c>Activating cell preservation system. Starting rapid freezing of Spriggan Factors in concentration.</color>","TWN":"<color=#ffd34c>細胞保存系統啟動。守護者因子集束，冷凍開始。</color>"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>동결해제 시점… 명령권자의 접촉이 있을 때까지.</color>","JPN":"<color=#ffd34c>凍結解除時点……命令権者との接触があるまで。</color>","ENG":"<color=#ffd34c>Unfreezing only when... coming into contact with the commander.</color>","TWN":"<color=#ffd34c>解凍日期為……直到指揮官聯繫為止。</color>"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사고 프로세스를 중지하고 휴면모드로 전환합니다.</color>","JPN":"<color=#ffd34c>思考プロセスを中止して休眠モードに切り替えます。</color>","ENG":"<color=#ffd34c>Suspending thought process and going into hibernation mode.</color>","TWN":"<color=#ffd34c>中斷思維程式，進入睡眠模式。</color>"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>외부로부터 강력한 전자기 펄스를 감지.</color>","JPN":"<color=#ffd34c>外部から強力な電磁気パルスを感知。</color>","ENG":"<color=#ffd34c>Detecting strong electromagnetic pulses from the outside.</color>","TWN":"<color=#ffd34c>感應到來自外部的強電磁脈衝。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L28_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>충격으로 비활성화된 세포보존기능을 복원합니다.</color>","JPN":"<color=#ffd34c>衝撃により非活性化された細胞保存機能を復元します。</color>","ENG":"<color=#ffd34c>Restoring the cell preservation function disabled by the shock.</color>","TWN":"<color=#ffd34c>恢復因衝擊而關閉的細胞保存功能。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>시스템을 복원하는 동안, 사고 프로세스가 일시적으로 기능할 수 있습니다.</color>","JPN":"<color=#ffd34c>システムを復元する間、思考プロセスを一時的に機能できます。</color>","ENG":"<color=#ffd34c>While the system is restoring, thought process will be temporarily functional.</color>","TWN":"<color=#ffd34c>系統恢復期間，思維程式將會暫時失效。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"여긴… 어디지?","JPN":"ここは……どこ？","ENG":"What is this place…?","TWN":"這個地方……是哪裡？"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"날 부르는 목소리가 들려…","JPN":"シェパードを呼ぶ声がする……","ENG":"Shepherd hears someone calling...","TWN":"有一個聲音在呼喚牧羊犬……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"그리운 풍경… 그리운 목소리…","JPN":"懐かしい風景……懐かしい声……","ENG":"A nostalgic scenery... and voice...","TWN":"讓人懷念的風景……讓人懷念的聲音……"},"stage":{"bg":"WHITE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L37_1","type":"dialog","speaker":null,"text":{"KOREA":"운이 좋았네. 한겨울에 딸기를 팔다니 말이야.","JPN":"運がよかったわね。真冬にイチゴを売ってるなんて。","ENG":"We were lucky. Finding someone who sells strawberries in the middle of winter.","TWN":"今天運氣很不錯呢。冬天還能遇見賣草莓的。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L38_1","type":"dialog","speaker":null,"text":{"KOREA":"엄마가 해준 스무디가 그렇게 맛있어?","JPN":"お母さんのスムージー、そんなに美味しい？","ENG":"Do you like the smoothie I made you that much?","TWN":"媽媽做的冰沙有那麼好吃嗎？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":null,"text":{"KOREA":"차가워. 이게 스무디라는 거구나.","JPN":"冷たい。これがスムージーなんだ。","ENG":"It's cold. So this is what a smoothie is.","TWN":"好冰。這就是冰沙啊。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"그런데… 저 사람은 왜 저렇게 슬픈 마음으로 날 바라보는 걸까?","JPN":"でも……あの人はどうしてあんなに悲しい心でシェパードを見つめてるの?","ENG":"But... why is that person looking at Shepherd so sadly?","TWN":"但是……為什麼那個人用非常悲傷的眼神看著牧羊犬？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 맞아.","JPN":"あ、そうだ。","ENG":"Oh, right.","TWN":"啊，牧羊犬想起來了。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":null,"text":{"KOREA":"그건 내가 먹는 딸기 스무디가 달콤하지 않았기 때문이야.","JPN":"きっとシェパードが飲んでるイチゴスムージーが甘くなかったからだ。","ENG":"That's because the smoothie Shepherd's having isn't sweet.","TWN":"是因為牧羊犬覺得草莓冰沙不夠甜。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":null,"text":{"KOREA":"하지만 달콤하다는 건 뭐지?","JPN":"でも、甘いって何？","ENG":"But what is sweet?","TWN":"但是，什麼是甜？"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":null,"text":{"KOREA":"그게 뭔진 모르지만 미안해요.","JPN":"それが何なのかわからないけど、ごめんなさい。","ENG":"Shepherd doesn't know what that is. Sorry.","TWN":"對不起，牧羊犬不知道這些。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":null,"text":{"KOREA":"좀 더 맛있게 먹지 못해서 미안해요.","JPN":"もっと美味しく飲めなくてごめんなさい。","ENG":"Shepherd's sorry that Shepherd couldn't enjoy it more.","TWN":"很抱歉，牧羊犬沒能吃出它的美味。"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까…","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"웃는 표정으로 그렇게 슬퍼하지 말아요.","JPN":"笑顔でそんなに悲しまないで。","ENG":"don't smile at Shepherd with such a sad face.","TWN":"別再那樣對著牧羊犬悲傷地笑了……"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>책임자의 권한 접속 확인- 휴면모드 해제-</color>","JPN":"<color=#ffd34c>責任者の権限接続を確認……休眠モードを解除。</color>","ENG":"<color=#ffd34c>Supervisor Authority Access Confirmed - Hibernation mode disabled -</color>","TWN":"<color=#ffd34c>確認到負責人的存取權限 - 睡眠模式已禁用</color>"},"stage":{"bg":"DORMITORY_2","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_15"},{"id":"L5_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"셰퍼드. 쉬고 있는데 방해해서 미안해.","JPN":"シェパード。休んでるところ邪魔してごめん。","ENG":"Shepherd. I'm sorry to bother you while you're sleeping.","TWN":"牧羊犬。很抱歉在你休息時打擾你。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"오래 기다렸지?","JPN":"結構待っただろ？","ENG":"Did you wait long?","TWN":"你等了很久了吧？"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"아니. 푹 잤어요.","JPN":"ううん。ぐっすり寝てたよ。","ENG":"No, Shepherd slept well.","TWN":"沒有。牧羊犬睡得很香。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"꿈도 꾼 걸요.","JPN":"夢も見たしね。","ENG":"Even had a dream.","TWN":"還做了一個夢。"},"stage":{"bg":"WAREHOUSE_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"헉 헉…","JPN":"はあ、はあ……","ENG":"*Huff* *Huff*","TWN":"呼……咳咳……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L13_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"이쪽으로… 가자.","JPN":"こっちに……行こう。","ENG":"Let's go... this way.","TWN":"我們走吧……來這邊。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"아파요?","JPN":"痛い？","ENG":"Does it hurt?","TWN":"你很痛嗎？"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"아니… 난… 괜찮아.","JPN":"いや……僕は……大丈夫。","ENG":"No... I'm... okay.","TWN":"不……我……沒事。"},"stage":{"bg":"BASEMENT","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NULL_ONLY","face":"UNIT_IDLE"},"R":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"셰퍼드. 지금부터 내 말 잘 들어.","JPN":"シェパード。今から僕の話をよく聞いてくれ。","ENG":"Shepherd, listen carefully to what I'm about to say.","TWN":"牧羊犬。從現在開始，你要認真聽我說。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"아무래도 난 충전이 필요해서… 너와 함께 나가지 못할 것 같아.","JPN":"どうやら僕は充電が必要で……君と一緒に出られないようだ。","ENG":"I need to recharge, so... I won't be able to go with you.","TWN":"我需要去充電了……不能和你一起走了。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"그러니 선물을 품에서 절대 놓지 말고, 내가 예전에 말한 주소를 찾아가렴.","JPN":"だから、プレゼントを手離さないで、僕が昔言った住所に行ってくれ。","ENG":"So hold on to this gift and head to the address I mentioned before.","TWN":"所以，千萬要把禮物拿好了，去找我之前告訴過你的地址。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"할 수 있겠지?","JPN":"できるよな？","ENG":"Can you do that for me?","TWN":"你能做到的，對吧？"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"안돼요.","JPN":"ダメだよ。","ENG":"No.","TWN":"牧羊犬不要。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"셰퍼드. 이건 명령이야.","JPN":"これは命令権者の命令だ。","ENG":"This is an order from your commander.","TWN":"這是指揮官的命令。"},"stage":{"bg":"FLOOR_FACILITY_02","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"명령권자의 명령은 절대적.","JPN":"命令権者の命令は絶対。","ENG":"Commander's orders are absolute.","TWN":"指揮官的的命令不可違抗。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"그치만 셰퍼드는요. <color=#ffd34c>날 아끼는 사람</color>과 여기 숨어있기로 먼저 약속했어요.","JPN":"でもシェパードはね。<color=#ffd34c>シェパードを大切に思っている人</color>とここに隠れているって約束したの。","ENG":"But Shepherd... Shepherd promised <color=#ffd34c>the person dear to Shepherd</color> first to hide here.","TWN":"可是牧羊犬，和<color=#ffd34c>在乎她的人</color>人有過約定，會藏在這裡。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":null,"text":{"KOREA":"약속은 멀리 떨어져 있어도, 서로의 마음을 이어주는 소중한 계약.","JPN":"約束はどんなに遠く離れていても、お互いの心を繋げてくれる契約。","ENG":"A promise is a contract that connects each other's hearts, no matter how far apart they are.","TWN":"約定是珍貴的契約，即使相距遙遠，也能將彼此的心連在一起。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L32_1","type":"dialog","speaker":null,"text":{"KOREA":"셰퍼드는 그 사람이 깨어날 때까지 약속 지킬 거예요.","JPN":"シェパードはあの人が目を覚ますまで約束を守る。","ENG":"Shepherd will keep this promise until he wakes up again.","TWN":"牧羊犬會遵守約定，直到那個人醒來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"그러니까…","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"얼른 일어나요.","JPN":"早く起きて。","ENG":"please wake up soon.","TWN":"請快點醒來吧。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>다음은 마지막 메시지입니다.</color>","JPN":"<color=#ffd34c>次は、最後のメッセージです。</color>","ENG":"<color=#ffd34c>This is the last message.</color>","TWN":"<color=#ffd34c>這是最後一段記錄了。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L43_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>5년. 길다면 너무도 길고, 짧다면 짧은 시간이었지.</color>","JPN":"<color=#ffd34c>5年。長いといえばあまりにも長く、短いと言えば短い時間だった。</color>","ENG":"<color=#ffd34c>Five years. The time can be long or short depending on how you see it.</color>","TWN":"<color=#ffd34c>五年的時間，說長不長，說短不短。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L44_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>미안해. 다이앤.</color>","JPN":"<color=#ffd34c>ごめんな。ダイアン。</color>","ENG":"<color=#ffd34c>I'm sorry, Diana.</color>","TWN":"<color=#ffd34c>對不起。黛安娜</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>혼자 남은 당신에겐 이 5년이 얼마나 고통스러웠을지… 감히 이해한다고 말하지 않을게.</color>","JPN":"<color=#ffd34c>一人で残った君には、この5年がどれほど苦しかったか……理解できるなんて言えないな。</color>","ENG":"<color=#ffd34c>I can't imagine how lonely and painful... those five years must have been for you.</color>","TWN":"<color=#ffd34c>這五年，對於孤身一人的你來說該是多麼痛苦……我不敢說我​​明白。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>하지만 나에게 이 물건을 찾는 5년은 정말이지 촉박했어. 그 아이가 날 얼마나 더 기다릴 수 있을지, 확신이 없었으니까.</color>","JPN":"<color=#ffd34c>でも、僕にはこれを探している5年間は本当に切実だった。あの子が僕のことをどれほど待っていられるか、確信がなかったから。</color>","ENG":"<color=#ffd34c>But for me, these five years to find this object was a race against time. Because I wasn't sure how much longer she would wait for me.</color>","TWN":"<color=#ffd34c>但對我來說，尋找東西的這五年真的太長了。我不知道她還能等我多久。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"당신을 만나면 물어볼 게 참 많았어, 에드윈.","JPN":"あなたに会ったら、たくさん聞きたかった、エッドウィン。","ENG":"I had a lot of questions to ask you, Edwin.","TWN":"我曾有很多問題想要當面問你，艾德溫。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런데, 여기까지 오니까… 그 질문들이 다 쓸모없어졌네.","JPN":"でも、ここまで来て……全部無駄になってしまったね。","ENG":"But after coming this far... all those questions seem useless now.","TWN":"但事到如今……這些問題都沒有用了。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>상자에 든 건, 내가 찾아낸 작은 청동나무로 만든 심장이야. 스프리건 인자에겐 둥지와 같은 존재지.</color>","JPN":"<color=#ffd34c>ボックスに入ってるのは、僕が見つけた小さな青銅の木で作った心臓だ。スプリガン因子の巣のようなものだよ。</color>","ENG":"<color=#ffd34c>Inside the box, there is a heart that I made from a small Bronze Tree I found. It acts like a nest for the Spriggan Factor.</color>","TWN":"<color=#ffd34c>盒子裡裝的，是我用找到的一顆小青銅樹做的心臟。它就像是守護者因子的巢穴。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>이걸 셰퍼드의 심장에 이식하면 스프리건 인자는 안정을 되찾을 테고, 그 아이는 살아남을 수 있겠지.</color>","JPN":"<color=#ffd34c>これをシェパードの心臓に移植すれば、スプリガン因子が安定して、その子は生き残れるだろう。</color>","ENG":"<color=#ffd34c>Implanting this heart into Shepherd will stabilize the Spriggan Factor, allowing her to live.</color>","TWN":"<color=#ffd34c>如果將它移植到牧羊犬的心臟裡，守護者因子就會變得穩定，那個孩子就能活下來。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그렇게 생각하면… 그냥 당신이 직접 하지 그랬어?","JPN":"そう思ったなら……あなたが直接やればよかったじゃない。","ENG":"If you thought it would work... then why didn't you do it yourself?","TWN":"如果你這麼認為的話……為什麼不自己動手呢？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"이젠 너무 멀리 와서 돌이킬 수도 없는데 말이야.","JPN":"こんなに遠くまで来て、もう後戻りもできないのに。","ENG":"You had already gone too far and couldn't go back.","TWN":"你已經走了太遠，無法回頭了。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>그런데 말이야. 차마 할 수가 없었어.</color>","JPN":"<color=#ffd34c>でも、できなかったんだ。</color>","ENG":"<color=#ffd34c>But you know, I just couldn't do it.</color>","TWN":"<color=#ffd34c>不過，我實在不忍心。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L8_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>아이를 살리려고 그렇게 많은 시술을 했는데…</color>","JPN":"<color=#ffd34c>あの子を生かすために、あそこまでたくさん施術したのに……</color>","ENG":"<color=#ffd34c>I performed so many surgeries to save her...</color>","TWN":"<color=#ffd34c>為了救我們的孩子，我做了這麼多手術……</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>5년 동안 이면세계를 돌아다녔는데…</color>","JPN":"<color=#ffd34c>5年間、裏世界中を回ったのに……</color>","ENG":"<color=#ffd34c>searching up and down the Counterside for five years...</color>","TWN":"<color=#ffd34c>在異界流浪了五年……</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>차마 그 아이의 심장마저 바꾸는 짓은 할 수가 없었어.</color>","JPN":"<color=#ffd34c>あの子の心臓を取り替えるなんてできなかったんだよ。</color>","ENG":"<color=#ffd34c>But I just couldn't bear the thought of replacing her heart.</color>","TWN":"<color=#ffd34c>我不忍心，連那個孩子原本的心臟都要被換掉。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"하.","JPN":"はあ。","ENG":"Ha.","TWN":"呵。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"뒤늦은 반성이야?","JPN":"今さら何を反省してるんだ？","ENG":"Is this your belated reflection?","TWN":"這是遲來的反省嗎？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나한테 다 떠맡기고 죽어버리면… 마음이 편해?","JPN":"全部私に押しつけて死んじゃうなんて……さぞ気が楽だろうね？","ENG":"If you leave everything to me and die... do you feel at ease?","TWN":"現在把一切都推給我，自己去死……就能安心了嗎？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>아이를 붙잡지 않는 게 옳았을 지도 몰라.</color>","JPN":"<color=#ffd34c>あの子を手放したほうがよかったのかもしれない。</color>","ENG":"<color=#ffd34c>Maybe it was right not to hold her back.</color>","TWN":"<color=#ffd34c>也許我們不該強留住她。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L16_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>남은 시간이 얼마나 있든… 아이와 함께 조금이라도 더 시간을 보내는 편이 좋았을 지도 몰라.</color>","JPN":"<color=#ffd34c>残った時間がいくらあろうと……少しでもあの子と一緒にいたほうがよかったのかもしれない。</color>","ENG":"<color=#ffd34c>No matter how much time we had left... spending what little time we had with her might've been for the better.</color>","TWN":"<color=#ffd34c>不管她還剩下多少時間……多花點時間陪伴她也許會更好。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>그런데 말이야…</color>","JPN":"<color=#ffd34c>だけど……</color>","ENG":"<color=#ffd34c>But still...</color>","TWN":"<color=#ffd34c>但是……</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>그땐 붙잡고 싶었어.</color>","JPN":"<color=#ffd34c>あの時は諦めきれなかった。</color>","ENG":"<color=#ffd34c>I wanted to hold on to her back then.</color>","TWN":"<color=#ffd34c>那個時候的我放不了手。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>가족여행이란 그 쉬운 소원 하나 못 들어준 내가 너무 싫어서…</color>","JPN":"<color=#ffd34c>家族旅行に行くという、そんな簡単な願いも叶えてあげられなかった僕自身があまりにも嫌で……</color>","ENG":"<color=#ffd34c>I hated myself for not being able to take her on something as easy as a family trip...</color>","TWN":"<color=#ffd34c>我恨自己，連家族旅行這種簡單的願望也沒能滿足她……</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L23_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>자기 생일을 기다리는 것마저 잊어버린 그 아이가 너무 불쌍해서…</color>","JPN":"<color=#ffd34c>自分の誕生日を待つことすら忘れてしまったあの子が可哀想すぎて……</color>","ENG":"<color=#ffd34c>I felt sorry for her, who even forgot when her birthday was...</color>","TWN":"<color=#ffd34c>我很心疼那個連自己生日都忘了的孩子……</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>그래서…</color>","JPN":"<color=#ffd34c>それで……</color>","ENG":"<color=#ffd34c>That's why...</color>","TWN":"<color=#ffd34c>所以……</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>…다시 한 번, 모든 걸 돌려받고 싶었어.</color>","JPN":"<color=#ffd34c>……もう一度、すべてを取り返したかったんだ。</color>","ENG":"<color=#ffd34c>I wanted everything back, just one more time...</color>","TWN":"<color=#ffd34c>……我再一次地，想要挽回這一切。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"누군 안 그런 줄 알아?","JPN":"それは私だって一緒だ。","ENG":"And you think I don't?","TWN":"誰不是這樣呢？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"나도 붙잡아보려 했어.","JPN":"私だって諦めたくなかった。","ENG":"I tried too, you know.","TWN":"我也試圖抓住她。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"안되는 줄 알면서도, 치료제를 만들겠다고 온종일 연구에만 매달렸어.","JPN":"ダメだとわかってても、治療剤を作るために一日中研究した。","ENG":"I knew it wouldn't work, but I devoted my time to creating a cure.","TWN":"盡管知道沒用，但還是整天把自己關在研究室裡研究治療方法。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아이는 혼자 병실에서 우릴 기다리고 있었을 텐데…","JPN":"あの子は病室で、ただ一人で私たちを待っていたのに……","ENG":"I knew she was waiting for us all alone in that hospital room...","TWN":"留孩子獨自在病房裡等著我們……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"난 그걸 알면서도 외면했어.","JPN":"私はそれを知ってながらも目を背けてしまった。","ENG":"but I looked away.","TWN":"我明明知道，卻還是選擇了逃避。"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그런데 이게 뭐야.","JPN":"でも、何だ？","ENG":"But look at what happened.","TWN":"不過這算什麼？"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"죄는 우리가 지었는데, 당신 혼자 이러고 있으면 안 되는 거잖아.","JPN":"罪は私たち二人で犯したのに、あなただけがこんな目に遭うだなんて。","ENG":"We both sinned… Don't act like you're responsible for it all.","TWN":"錯是我們兩個人犯下的，要擔當然一起擔……"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>5년만에 남긴 말이 이런 거라… 미안해.</color>","JPN":"<color=#ffd34c>5年ぶりのこんな話をして……悪かった。</color>","ENG":"<color=#ffd34c>I'm sorry... for telling you all this after five years.</color>","TWN":"<color=#ffd34c>時隔五年，我最後卻留下這些話……對不起。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L37_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>이런 일을 당신에게 떠넘긴 것도 미안해.</color>","JPN":"<color=#ffd34c>こんなことを君に押しつけたのも悪かったよ。</color>","ENG":"<color=#ffd34c>I'm sorry that I'm leaving this mess to you.</color>","TWN":"<color=#ffd34c>我很抱歉把這些事情推給你。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EDWIN_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>있잖아. 다이앤…</color>","JPN":"<color=#ffd34c>ダイアン……</color>","ENG":"<color=#ffd34c>You know, Diana...</color>","TWN":"<color=#ffd34c>黛安娜……</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>만약 당신의 결정으로 그 아이가 다시 깨어난다면…</color>","JPN":"<color=#ffd34c>もし君の決定で、あの子が再び目を覚ましたら……</color>","ENG":"<color=#ffd34c>If she wakes up due to your decision...</color>","TWN":"<color=#ffd34c>如果你決定讓那個孩子再次醒來……</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>내 얘기는 하지 말아줘.</color>","JPN":"<color=#ffd34c>僕の話はしないでくれ。</color>","ENG":"<color=#ffd34c>don't tell her about me.</color>","TWN":"<color=#ffd34c>請不要跟她提起我。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>그 아이가 상실감을 느끼지 않게 해줘.</color>","JPN":"<color=#ffd34c>あの子が悲しまないように。</color>","ENG":"<color=#ffd34c>I don't want her to feel the sense of loss.</color>","TWN":"<color=#ffd34c>不要讓孩子感到失落。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>그냥 당신이… </color>","JPN":"<color=#ffd34c>ただ……</color>","ENG":"<color=#ffd34c>Just tell her that...</color>","TWN":"<color=#ffd34c>就告訴她……</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"EDWIN_FLOOR_NULL_EXOSUIT","text":{"KOREA":"<color=#ffd34c>널 아끼는 사람이 곁에 있단 것만 알려줘.</color>","JPN":"<color=#ffd34c>シェパードを大切に思ってる人がそばにいるってことだけを伝えてくれ。</color>","ENG":"<color=#ffd34c>the person dear to her is next to her.</color>","TWN":"<color=#ffd34c>你就告訴她，曾經有個在乎她的人就行了。</color>"},"stage":{"bg":"FLOOR_01","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>엄마.</color>","JPN":"<color=#ffd34c>お母さん。</color>","ENG":"<color=#ffd34c>Mommy?</color>","TWN":"<color=#ffd34c>媽媽。</color>"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>나 좀 있으면 생일 선물 받을 수 있죠?</color>","JPN":"<color=#ffd34c>私、もうちょっとしたら誕生日プレゼントもらえるの？</color>","ENG":"<color=#ffd34c>I'll be getting my birthday present soon, right?</color>","TWN":"<color=#ffd34c>再過不久，我就可以得到生日禮物了嗎？</color>"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>내 친구들은 생일이 되면 다 같이 집에 모여서 생일파티 연대요.</color>","JPN":"<color=#ffd34c>友だちは誕生日にみんなでおウチに集まって誕生日パーティーをするんだって。</color>","ENG":"<color=#ffd34c>My friends tell me that they gather at their houses and have a birthday party on their birthdays.</color>","TWN":"<color=#ffd34c>我的朋友他們過生日，都會在家裡舉辦生日派對。</color>"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>예쁜 옷 입고, 맛있는 것도 먹고, 선물도 잔뜩 받는데요.</color>","JPN":"<color=#ffd34c>かわいい服を着て、美味しいものも食べて、プレゼントもいっぱいもらえるんだって。</color>","ENG":"<color=#ffd34c>They wear pretty clothes, eat tasty food, and receive tons of presents.</color>","TWN":"<color=#ffd34c>穿著漂亮的衣服，吃著美味的食物，還能收到很多禮物。</color>"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>응, 알아요. 나 집에 못 가는 거.</color>","JPN":"<color=#ffd34c>うん、わかってるよ。おウチに帰れないよね。</color>","ENG":"<color=#ffd34c>But I know. That I can't go home.</color>","TWN":"<color=#ffd34c>我知道，我不能回家。</color>"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>엄마, 아빠도 모두 일 때문에 바쁘니까… 생일파티는 힘들다는 것도 알아요.</color>","JPN":"<color=#ffd34c>お母さん、お父さんもみんな仕事で忙しいから……誕生日パーティーは難しいってこともわかってる。</color>","ENG":"<color=#ffd34c>Mommy and Daddy are both busy because of work... so I know it'll be hard to have a birthday party.</color>","TWN":"<color=#ffd34c>你們的工作都很忙……我知道生日派對不太可能。</color>"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그러니까… 선물 하나만 주면 안 돼요?</color>","JPN":"<color=#ffd34c>だから……一つだけプレゼントちょうだい？</color>","ENG":"<color=#ffd34c>So instead... could I get a gift?</color>","TWN":"<color=#ffd34c>所以……可以送我一件禮物嗎？</color>"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>엄마랑 아빠, 셋이서 다 같이 가족여행 가고 싶어요.</color>","JPN":"<color=#ffd34c>お母さんとお父さんと、3人で一緒に家族旅行に行きたい。</color>","ENG":"<color=#ffd34c>I want to go on a family trip. Just the three of us. Mommy, Daddy, and me.</color>","TWN":"<color=#ffd34c>我想和家人一起去旅行。爸爸、媽媽，還有我，我們三個人的家族旅行。</color>"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>아빠랑 약속했어요. 엄마도 나도, 가족이 모두 함께 불꽃놀이를 봤으면 좋겠다고요.</color>","JPN":"<color=#ffd34c>お父さんとも約束したんだよ。お母さんと私と、家族みんなで一緒に花火見られたらいいねって。</color>","ENG":"<color=#ffd34c>Daddy promised. He said it would be nice for the whole family to go watch fireworks together.</color>","TWN":"<color=#ffd34c>我和爸爸已經約好了。我們，還有媽媽，我們一家人可以一起看煙火。</color>"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"그래…","JPN":"ああ……","ENG":"Sure...","TWN":"好啊……"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"그렇게 하자. 우리 소중한 딸.","JPN":"そうしましょう。私の大切な娘。","ENG":"Let's do that. My precious daughter.","TWN":"就照你說的辦吧。我的寶貝女兒。"},"stage":{"bg":"HOSPITAL","bgm":"THMEA_SAD_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>새로운 타입의 스프리건 인자 집속부 연결 확인.</color>","JPN":"<color=#ffd34c>新しいタイプのスプリガン因子集束部の接続を確認。</color>","ENG":"<color=#ffd34c>New type of Spriggan Factor concentration detected.</color>","TWN":"<color=#ffd34c>感應到新的守護者因子集束單元。</color>"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L14_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>신체 조율 완료. 사고 프로세스 활성화.</color>","JPN":"<color=#ffd34c>身体調律完了。思考プロセス活性化。</color>","ENG":"<color=#ffd34c>Adjusting body complete. Activating thought process.</color>","TWN":"<color=#ffd34c>身體協調完成。思維程式啟動。</color>"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP4"},{"id":"L17_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"안녕, 셰퍼드. 잘 잤니?","JPN":"おはよう、シェパード。よく寝た？","ENG":"Hello, Shepherd. Did you sleep well?","TWN":"你好，牧羊犬。睡得還好嗎？"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…응.","JPN":"……うん。","ENG":"...Uh-huh.","TWN":"……嗯。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"꿈을 꿨어요.","JPN":"夢を見たの。","ENG":"Shepherd had a dream.","TWN":"牧羊犬做了一個夢。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그런데, 잠에서 깨면 기억이 하나도 안 나서… 기분이 이상해요.","JPN":"でも、起きたら全然思い出せなくて……ヘンな感じ。","ENG":"But can't remember it after waking up... It feels weird.","TWN":"可是，牧羊犬醒來就不記得了……感覺好奇怪。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"꿈이란 건 원래 그런 거야.","JPN":"夢は元々そんなものだ。","ENG":"Dreams are like that.","TWN":"夢都是這樣的。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"꿈을 잊어버려야, 오늘 있었던 일들을 더 많이 기억할 수 있으니까.","JPN":"夢を忘れなければ、今日あったことをもっとたくさん覚えられないから。","ENG":"You have to forget about dreams so you can remember more about what happened today.","TWN":"忘記昨晚的夢，是為了記住更多今後發生的事情。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그렇구나.","JPN":"そうなんだ。","ENG":"Okay.","TWN":"原來是這樣。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"그럼 그냥 잊어버릴래요.","JPN":"じゃあ、忘れちゃう。","ENG":"Then Shepherd will just forget about it.","TWN":"那牧羊犬要忘記它。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPIRIT_RAS_NULL_ONLY","text":{"KOREA":"난 지금 당신을 볼 수 있어서 기쁘니까요.","JPN":"シェパードは今、あなたに会えて嬉しいから。","ENG":"Because Shepherd is happy to see you.","TWN":"因為牧羊犬現在很高興見到你。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"그래, 나도 기뻐.","JPN":"そう、私も嬉しい。","ENG":"Yeah, me too.","TWN":"嗯，我也很高興。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"네가 무사히 눈을 떠서… 정말 다행이야.","JPN":"あなたが無事に目覚めて……本当によかった。","ENG":"I'm just so relieved... that you woke up.","TWN":"你能平安醒來……我很高興。"},"stage":{"bg":"FLOOR_01","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};